package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class JsonWriterTest {

  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  void jsonValue_null_callsNullValue() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);
    doReturn(spyWriter).when(spyWriter).nullValue();

    JsonWriter result = spyWriter.jsonValue(null);

    verify(spyWriter).nullValue();
    assertSame(spyWriter, result);
  }

  @Test
  void jsonValue_nonNull_writesValue() throws Throwable {
    String testValue = "\"test\"";

    JsonWriter spyWriter = spy(jsonWriter);

    // Use reflection to stub private methods writeDeferredName() and beforeValue()
    Method writeDeferredNameMethod = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredNameMethod.setAccessible(true);
    doNothing().when(spyWriter).getClass().getDeclaredMethod("writeDeferredName");

    Method beforeValueMethod = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValueMethod.setAccessible(true);
    doNothing().when(spyWriter).getClass().getDeclaredMethod("beforeValue");

    // Instead of doNothing().when(spyWriter).writeDeferredName(); which fails due to private access,
    // we stub the methods via spy and reflection invoke in a custom Answer:
    doAnswer(invocation -> {
      // do nothing
      return null;
    }).when(spyWriter).getClass().getDeclaredMethod("writeDeferredName");

    doAnswer(invocation -> {
      // do nothing
      return null;
    }).when(spyWriter).getClass().getDeclaredMethod("beforeValue");

    // Since the above approach doesn't work with private methods directly,
    // we use a workaround: override the private methods by subclassing or use reflection to invoke jsonValue directly.
    // Here, we invoke jsonValue via reflection to avoid calling private methods directly.

    Method jsonValueMethod = JsonWriter.class.getDeclaredMethod("jsonValue", String.class);
    jsonValueMethod.setAccessible(true);

    JsonWriter result = (JsonWriter) jsonValueMethod.invoke(spyWriter, testValue);

    // Now verify the output string contains testValue
    assertEquals(testValue, stringWriter.toString());
    assertSame(spyWriter, result);
  }

  @Test
  void jsonValue_nonNull_actualWriteDeferredNameAndBeforeValue() throws IOException {
    // This test covers actual private methods indirectly by not mocking them.
    // We test that jsonValue appends the string to the writer.

    String testValue = "\"hello\"";

    JsonWriter writer = new JsonWriter(stringWriter);

    JsonWriter result = writer.jsonValue(testValue);

    assertEquals(testValue, stringWriter.toString());
    assertSame(writer, result);
  }

  @Test
  void jsonValue_reflectionInvoke() throws Throwable {
    String testValue = "\"reflect\"";

    Method jsonValueMethod = JsonWriter.class.getDeclaredMethod("jsonValue", String.class);
    jsonValueMethod.setAccessible(true);

    Object result = jsonValueMethod.invoke(jsonWriter, testValue);

    assertSame(jsonWriter, result);
    assertEquals(testValue, stringWriter.toString());
  }

  @Test
  void jsonValue_reflectionInvoke_null() throws Throwable {
    Method jsonValueMethod = JsonWriter.class.getDeclaredMethod("jsonValue", String.class);
    jsonValueMethod.setAccessible(true);

    Object result = jsonValueMethod.invoke(jsonWriter, new Object[] {null});

    assertNotNull(result);
    assertTrue(result instanceof JsonWriter);
  }
}
